41	namespace tf    = tensorflow;
42	namespace ft    = fastertransformer;
43	
44	template<typename T>
45	class BaseOp: public tf::OpKernel {
46	public:
47	    explicit BaseOp(tf::OpKernelConstruction* context): tf::OpKernel(context)
48	    {
49	        try {
50	            ft::check_cuda_error(cublasCreate(&cublas_handle_));
51	            ft::check_cuda_error(cublasLtCreate(&cublaslt_handle_));
52	            cublas_wrapper_mutex_ = new std::mutex();
53	        }
54	        catch (std::runtime_error& error) {
55	            OP_REQUIRES(context, false, tf::errors::Internal(error.what()));
56	        }
57	    };
58	
59	    ~BaseOp()
60	    {
61	        ft::check_cuda_error(cublasDestroy(cublas_handle_));
62	        ft::check_cuda_error(cublasLtDestroy(cublaslt_handle_));
63	        delete cublas_wrapper_mutex_;
64	    }
65	
66	protected:
67	    template<typename DataType_>
68	    void get_tensor(tf::OpKernelContext* context, int tensor_id, const DataType_** tensor_ptr, int off_set = 0)
69	    {
70	        *tensor_ptr = reinterpret_cast<const DataType_*>(context->input(tensor_id).flat<T>().data()) + off_set;
71	        OP_REQUIRES(context, *tensor_ptr != nullptr, tf::errors::InvalidArgument("tensor %d is null", tensor_id));
72	    }
73	
74	    template<typename DataType_>
75	    void get_tensor(tf::OpKernelContext* context, int tensor_id, DataType_** tensor_ptr, int off_set = 0)
76	    {
77	        *tensor_ptr = reinterpret_cast<DataType_*>(context->input(tensor_id).flat<T>().data()) + off_set;
78	        OP_REQUIRES(context, *tensor_ptr != nullptr, tf::errors::InvalidArgument("tensor %d is null", tensor_id));
79	    }
80	
81	    void get_tensor(tf::OpKernelContext* context, int tensor_id, const int** tensor_ptr, int off_set = 0)
82	    {
83	        *tensor_ptr = reinterpret_cast<const int*>(context->input(tensor_id).flat<int>().data()) + off_set;
84	        OP_REQUIRES(context, *tensor_ptr != nullptr, tf::errors::InvalidArgument("tensor %d is null", tensor_id));
85	    }
86	
87	    // convert the shape of TensorFlow Tensor to a vector
88	    std::vector<size_t> convert_shape(tf::Tensor tensor)
89	    {
90	        ft::FT_CHECK(tensor.dims() != -1);
91	        std::vector<size_t> v_shape;
92	        for (int i = 0; i < tensor.dims(); i++) {
93	            v_shape.push_back(tensor.dim_size(i));
94	        }
95	        return v_shape;
96	    }
97	
98	    // convert TensorFlow Tensor to FasterTransformer Tensor
99	    ft::Tensor convert_tensor(tf::Tensor tensor)
100	    {
101	        if (std::is_same<T, Eigen::half>::value == true) {
102	            return ft::Tensor{
103	                ft::MEMORY_GPU, ft::getTensorType<half>(), convert_shape(tensor), (half*)(tensor.flat<T>().data())};
104	        }
105	#ifdef ENABLE_BF16
106	        else if (std::is_same<T, Eigen::bfloat16>::value == true) {
107	            return ft::Tensor{ft::MEMORY_GPU,
108	                              ft::getTensorType<__nv_bfloat16>(),
109	                              convert_shape(tensor),
110	                              (__nv_bfloat16*)(tensor.flat<T>().data())};
111	        }
112	#endif
113	        else if (std::is_same<T, float>::value == true) {
114	            return ft::Tensor{
115	                ft::MEMORY_GPU, ft::getTensorType<float>(), convert_shape(tensor), (float*)(tensor.flat<T>().data())};
116	        }
117	        else {
118	            printf("[ERROR] Unknown data type \n");
119	            exit(-1);
120	        }
121	    }
122	
123	    // convert int type TensorFlow Tensor to FasterTransformer Tensor
124	    ft::Tensor convert_int_tensor(tf::Tensor tensor)
125	    {
126	        return ft::Tensor{ft::MEMORY_GPU, ft::TYPE_INT32, convert_shape(tensor), (int*)(tensor.flat<int>().data())};
127	    }
128	
129	    cublasHandle_t get_cublas_handler()
130	    {
131	        return cublas_handle_;
132	    }
133	    cublasLtHandle_t get_cublaslt_handler()
134	    {
135	        return cublaslt_handle_;
136	    }
137	
138	    std::mutex* get_cublas_wrapper_mutex()
139	    {
140	        return cublas_wrapper_mutex_;
141	    }
142	
143	private:
144	    cublasHandle_t   cublas_handle_;
145	    cublasLtHandle_t cublaslt_handle_;
146	    std::mutex*      cublas_wrapper_mutex_;
147	};
