17	#include "src/fastertransformer/models/bert/Bert.h"
18	#include "src/fastertransformer/tf_op/BaseOp.h"
19	
20	namespace ft = fastertransformer;
21	namespace tf = tensorflow;
22	
23	using CPUDevice = Eigen::ThreadPoolDevice;
24	using GPUDevice = Eigen::GpuDevice;
25	
26	REGISTER_OP("Bert")
27	    .Input("from_tensor: T")
28	    .Input("to_tensor: T")
29	    .Input("sequence_length: int32")
30	    .Input("attr_q_kernel: N * T")
31	    .Input("attr_q_bias: N * T")
32	    .Input("attr_k_kernel: N * T")
33	    .Input("attr_k_bias: N * T")
34	    .Input("attr_v_kernel: N * T")
35	    .Input("attr_v_bias: N * T")
36	    .Input("attr_output_kernel: N * T")
37	    .Input("attr_output_bias: N * T")
38	    .Input("attr_output_layernorm_beta: N * T")
39	    .Input("attr_output_layernorm_gamma: N * T")
40	    .Input("inter_kernel: N * T")
41	    .Input("inter_bias: N * T")
42	    .Input("output_kernel: N * T")
43	    .Input("output_bias: N * T")
44	    .Input("output_layernorm_beta: N * T")
45	    .Input("output_layernorm_gamma: N * T")
46	    .Output("output: T")
47	    .Attr("N: int")
48	    .Attr("T: {float, half}")
49	    .Attr("head_num: int >= 1")
50	    .Attr("size_per_head: int >= 1")
51	    .Attr("inter_size: int >= 1")
52	    .Attr("num_layer: int >= 1")
53	    .Attr("remove_padding: bool")
54	    .Attr("q_scaling: float")
55	    .SetShapeFn([](tf::shape_inference::InferenceContext* c) {
56	        c->set_output(0, c->input(0));
57	        return tf::Status::OK();
58	    });
59	
60	template<typename T>
61	class TFTraits;
62	
63	template<>
64	class TFTraits<float> {
65	public:
66	    typedef float DataType;
67	};
68	
69	template<>
70	class TFTraits<Eigen::half> {
71	public:
72	    typedef half DataType;
73	};
74	
75	#ifdef ENABLE_BF16
76	template<>
77	class TFTraits<Eigen::bfloat16> {
78	public:
79	    typedef __nv_bfloat16 DataType;
80	};
81	#endif
82	
83	template<typename Device, typename T>
84	class BertOp: public BaseOp<T> {
85	public:
86	    explicit BertOp(tf::OpKernelConstruction* context): BaseOp<T>(context)
87	    {
88	        try {
89	            OP_REQUIRES_OK(context, context->GetAttr("head_num", &head_num_));
90	            OP_REQUIRES_OK(context, context->GetAttr("size_per_head", &size_per_head_));
91	            OP_REQUIRES_OK(context, context->GetAttr("inter_size", &inter_size_));
92	            OP_REQUIRES_OK(context, context->GetAttr("num_layer", &num_layer_));
93	            OP_REQUIRES_OK(context, context->GetAttr("remove_padding", &remove_padding_));
94	            OP_REQUIRES_OK(context, context->GetAttr("q_scaling", &q_scaling_));
95	            sm_              = ft::getSMVersion();
96	            cublas_algo_map_ = new ft::cublasAlgoMap("gemm_config.in");
97	        }
98	        catch (std::runtime_error& error) {
99	            OP_REQUIRES(context, false, tf::errors::Internal(error.what()));
100	        }
101	    }
102	
103	    ~BertOp()
104	    {
105	        delete cublas_algo_map_;
106	    }
107	
108	    void Compute(tf::OpKernelContext* context) override
109	    {
110	        OP_REQUIRES(context,
111	                    context->num_inputs() == (num_layer_ * 16) + 3,
112	                    tf::errors::InvalidArgument("[ERROR] More or Less input arguments"));
113	
114	        const size_t batch_size_   = (size_t)context->input(0).dim_size(0);
115	        const size_t from_seq_len_ = (size_t)context->input(0).dim_size(1);
116	
117	        OP_REQUIRES(context,
118	                    batch_size_ == (size_t)context->input(2).dim_size(0),
119	                    tf::errors::InvalidArgument("[ERROR] invalid shape"));
120	
121	        const cudaStream_t& stream        = context->eigen_device<Device>().stream();
122	        cublasHandle_t      cublas_handle = this->get_cublas_handler();
123	        cublasSetStream(cublas_handle, stream);
124	        ft::Allocator<ft::AllocatorType::TF> allocator(context, stream);
125	        ft::cublasMMWrapper                  cublas_wrapper = ft::cublasMMWrapper(cublas_handle,
126	                                                                 this->get_cublaslt_handler(),
127	                                                                 stream,
128	                                                                 cublas_algo_map_,
129	                                                                 this->get_cublas_wrapper_mutex(),
130	                                                                 &allocator);
131	
132	        if (std::is_same<T, Eigen::half>::value) {
133	            cublas_wrapper.setFP16GemmConfig();
134	        }
135	#ifdef ENABLE_BF16
136	        else if (std::is_same<T, Eigen::bfloat16>::value) {
137	            cublas_wrapper.setBF16GemmConfig();
138	        }
139	#endif
140	        else if (std::is_same<T, float>::value) {
141	            cublas_wrapper.setFP32GemmConfig();
142	        }
143	
144	        ft::BertWeight<DataType> bert_weights;
145	        bert_weights.bert_layer_weights.resize(num_layer_);
146	
147	        for (int i = 0; i < num_layer_; i++) {
148	            this->get_tensor(context, 3 + i, &bert_weights.bert_layer_weights[i].attention_weights.query_weight.kernel);
149	            this->get_tensor(
150	                context, 3 + num_layer_ + i, &bert_weights.bert_layer_weights[i].attention_weights.query_weight.bias);
151	            this->get_tensor(context,
152	                             3 + num_layer_ * 2 + i,
153	                             &bert_weights.bert_layer_weights[i].attention_weights.key_weight.kernel);
154	            this->get_tensor(
155	                context, 3 + num_layer_ * 3 + i, &bert_weights.bert_layer_weights[i].attention_weights.key_weight.bias);
156	            this->get_tensor(context,
157	                             3 + num_layer_ * 4 + i,
158	                             &bert_weights.bert_layer_weights[i].attention_weights.value_weight.kernel);
159	            this->get_tensor(context,
160	                             3 + num_layer_ * 5 + i,
161	                             &bert_weights.bert_layer_weights[i].attention_weights.value_weight.bias);
162	            this->get_tensor(context,
163	                             3 + num_layer_ * 6 + i,
164	                             &bert_weights.bert_layer_weights[i].attention_weights.attention_output_weight.kernel);
165	            this->get_tensor(context,
166	                             3 + num_layer_ * 7 + i,
167	                             &bert_weights.bert_layer_weights[i].attention_weights.attention_output_weight.bias);
168	
169	            this->get_tensor(
170	                context, 3 + num_layer_ * 8 + i, &bert_weights.bert_layer_weights[i].attn_layernorm_weights.beta);
171	            this->get_tensor(
172	                context, 3 + num_layer_ * 9 + i, &bert_weights.bert_layer_weights[i].attn_layernorm_weights.gamma);
173	            this->get_tensor(context,
174	                             3 + num_layer_ * 10 + i,
175	                             &bert_weights.bert_layer_weights[i].ffn_weights.intermediate_weight.kernel);
176	            this->get_tensor(context,
177	                             3 + num_layer_ * 11 + i,
178	                             &bert_weights.bert_layer_weights[i].ffn_weights.intermediate_weight.bias);
179	            this->get_tensor(
180	                context, 3 + num_layer_ * 12 + i, &bert_weights.bert_layer_weights[i].ffn_weights.output_weight.kernel);
181	            this->get_tensor(
182	                context, 3 + num_layer_ * 13 + i, &bert_weights.bert_layer_weights[i].ffn_weights.output_weight.bias);
183	            this->get_tensor(
184	                context, 3 + num_layer_ * 14 + i, &bert_weights.bert_layer_weights[i].ffn_layernorm_weights.beta);
185	            this->get_tensor(
186	                context, 3 + num_layer_ * 15 + i, &bert_weights.bert_layer_weights[i].ffn_layernorm_weights.gamma);
187	        }
188	        bert_weights.post_transformer_layernorm_weights.gamma = nullptr;
189	        bert_weights.post_transformer_layernorm_weights.beta  = nullptr;
190	
191	        ft::AttentionType attention_type =
192	            ft::getAttentionType<DataType>(size_per_head_, sm_, remove_padding_, from_seq_len_);
193	
194	        ft::Bert<DataType> bert = ft::Bert<DataType>(batch_size_,
195	                                                     from_seq_len_,
196	                                                     head_num_,
197	                                                     size_per_head_,
198	                                                     inter_size_,
199	                                                     num_layer_,
200	                                                     sm_,
201	                                                     q_scaling_,
202	                                                     stream,
203	                                                     &cublas_wrapper,
204	                                                     &allocator,
205	                                                     true,
206	                                                     attention_type,
207	                                                     false,
208	                                                     ft::ActivationType::Gelu,
209	                                                     ft::LayerNormType::post_layernorm);
210	
211	        tf::Tensor* output = nullptr;
212	        OP_REQUIRES_OK(context, context->allocate_output(0, context->input(0).shape(), &output));
213	        DataType* out_tensor = reinterpret_cast<DataType*>(output->flat<T>().data());
214	
215	        ft::DataType            data_type     = ft::getTensorType<DataType>();
216	        std::vector<ft::Tensor> input_tensors = std::vector<ft::Tensor>{this->convert_tensor(context->input(0)),
217	                                                                        this->convert_int_tensor(context->input(2))};
218	
219	        std::vector<ft::Tensor> output_tensors = std::vector<ft::Tensor>{
220	            ft::Tensor{ft::MEMORY_GPU,
221	                       data_type,
222	                       std::vector<size_t>{batch_size_, from_seq_len_, (size_t)(head_num_ * size_per_head_)},
223	                       out_tensor}};
224	
225	        try {
226	            bert.forward(&output_tensors, &input_tensors, &bert_weights);
227	        }
228	        catch (std::runtime_error& error) {
229	            std::cout << tf::errors::Internal(error.what());
230	            ft::FT_CHECK(false);
231	        }
232	        catch (...) {
233	            std::cout << tf::errors::Internal("Runtime error");
234	            ft::FT_CHECK(false);
235	        }
236	    }
237	
238	private:
239	    int                                head_num_ = 0, size_per_head_ = 0, inter_size_ = 0, num_layer_ = 0;
240	    float                              q_scaling_ = 1.0f;
241	    bool                               remove_padding_;
242	    int                                sm_;
243	    ft::cublasAlgoMap*                 cublas_algo_map_;
244	    typedef TFTraits<T>                traits_;
245	    typedef typename traits_::DataType DataType;
246	};
247	
248	#ifdef GOOGLE_CUDA
249	
250	#define REGISTER_GPU(T)                                                                                                \
251	    REGISTER_KERNEL_BUILDER(Name("Bert").Device(tf::DEVICE_GPU).TypeConstraint<T>("T"), BertOp<GPUDevice, T>)
252	REGISTER_GPU(float);
253	REGISTER_GPU(Eigen::half);
254	#undef REGISTER_GPU
255	
256	#endif
