329	        input_tensors.insert({"repetition_penalty",
330	                              ft::Tensor{ft::MEMORY_CPU, ft::TYPE_FP32, std::vector<size_t>{1}, &repetition_penalty_}});
331	        uint64_t random_seed = 0;
332	        input_tensors.insert(
333	            {"random_seed", ft::Tensor{ft::MEMORY_CPU, ft::TYPE_UINT64, std::vector<size_t>{1}, &random_seed}});
334	
335	        std::vector<int> total_output_length_vec(batch_size, total_output_length);
336	        input_tensors.insert(
337	            {"output_seq_len",
338	             ft::Tensor{
339	                 ft::MEMORY_CPU, ft::TYPE_UINT32, std::vector<size_t>{batch_size}, total_output_length_vec.data()}});
340	
341	        std::unordered_map<std::string, ft::Tensor> output_tensors = std::unordered_map<std::string, ft::Tensor>{
342	            {"output_ids",
343	             ft::Tensor{ft::MEMORY_GPU,
344	                        ft::TYPE_INT32,
345	                        std::vector<size_t>{batch_size, (size_t)beam_width_, (size_t)total_output_length},
346	                        output_ids}},
